// Color per badge key
const BADGE_COLORS = {
  first_login: C.green,
  broker_connected: C.blue,
  first_watchlist: C.purple,
  alert_master: C.amber,
  backtest_pro: C.blue,
  strategy_explorer: C.purple,
  week_streak: C.amber,
  power_trader: C.green,
  // Engagement badges
  first_trade: C.green,
  strategy_scout: C.cyan,
  data_nerd: C.blue,
  night_owl: C.purple,
  global_trader: C.amber,
};

const CACHE_KEY = 'aura_achievements_cache';
const LOCAL_BADGE_KEY = 'aura_local_badges';
const LOCAL_PROGRESS_KEY = 'aura_badge_progress';

// ── Client-side badge definitions ──────────────────────────────────────────
const LOCAL_BADGE_DEFS = [
  {
    key: 'first_trade',
    label: 'First Trade',
    description: 'Placed your first paper or live order',
    threshold: 1,
    progressKey: 'trades_placed',
  },
  {
    key: 'strategy_scout',
    label: 'Strategy Scout',
    description: 'Viewed 10+ strategies',
    threshold: 10,
    progressKey: 'strategies_viewed',
  },
  {
    key: 'data_nerd',
    label: 'Data Nerd',
    description: 'Checked charts 50 times',
    threshold: 50,
    progressKey: 'charts_viewed',
  },
  {
    key: 'night_owl',
    label: 'Night Owl',
    description: 'Logged in after midnight',
    threshold: 1,
    progressKey: 'midnight_logins',
  },
  {
    key: 'global_trader',
    label: 'Global Trader',
    description: 'Viewed strategies from 3+ regions',
    threshold: 3,
    progressKey: 'regions_viewed',
  },
];

function getLocalProgress() {
  try {
    return JSON.parse(localStorage.getItem(LOCAL_PROGRESS_KEY) || '{}');
  } catch { return {}; }
}

function getLocalBadges() {
  try {
    return JSON.parse(localStorage.getItem(LOCAL_BADGE_KEY) || '{}');
  } catch { return {}; }
}

// Track progress for a badge counter. Call from anywhere via:
// window.dispatchEvent(new CustomEvent('aura:badge-progress', { detail: { key: 'charts_viewed' } }))
function handleBadgeProgress(progressKey, increment = 1) {
  const progress = getLocalProgress();
  const current = (progress[progressKey] || 0) + increment;
  progress[progressKey] = current;
  localStorage.setItem(LOCAL_PROGRESS_KEY, JSON.stringify(progress));

  // Check if any badge should be unlocked
  const earned = getLocalBadges();
  for (const def of LOCAL_BADGE_DEFS) {
    if (def.progressKey === progressKey && !earned[def.key] && current >= def.threshold) {
      earned[def.key] = { earned_at: Math.floor(Date.now() / 1000) };
      localStorage.setItem(LOCAL_BADGE_KEY, JSON.stringify(earned));
    }
  }
}

// Auto-check Night Owl on mount
function checkNightOwl() {
  const hour = new Date().getHours();
  if (hour >= 0 && hour < 5) {
    handleBadgeProgress('midnight_logins', 1);
  }
}

function formatDate(ts) {
  if (!ts) return '';
  const d = new Date(ts * 1000);
  return d.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
}

export default function AchievementBadges() {
  const [badges, setBadges] = useState([]);
  const [earned, setEarned] = useState(0);
  const [total, setTotal] = useState(8);
  const [tooltip, setTooltip] = useState(null); // badge key
  const [loading, setLoading] = useState(true);
  const [localBadgeState, setLocalBadgeState] = useState({});

  // Listen for badge progress events from other components
  useEffect(() => {
    checkNightOwl();

    const handler = (e) => {
      const { key, increment } = e.detail || {};
      if (key) handleBadgeProgress(key, increment || 1);
      // Re-read local badges to trigger re-render
      setLocalBadgeState({ ...getLocalBadges() });
    };
    window.addEventListener('aura:badge-progress', handler);
    setLocalBadgeState(getLocalBadges());
    return () => window.removeEventListener('aura:badge-progress', handler);
  }, []);

  useEffect(() => {
    let cancelled = false;

    async function fetchBadges() {
      try {
        const token = localStorage.getItem('aura_token');
        const headers = {};
        if (token) headers.Authorization = `Bearer ${token}`;
        const res = await fetch(`${getApiBase()}/achievements`, { headers });
        if (!res.ok) throw new Error('API failed');
        const data = await res.json();
        if (!cancelled) {
          setBadges(data.badges || []);
          setEarned(data.earned || 0);
          setTotal(data.total || 8);
          // Cache for offline fallback
          localStorage.setItem(CACHE_KEY, JSON.stringify(data));
        }
      } catch {
        // Fallback to localStorage cache
        try {
          const cached = localStorage.getItem(CACHE_KEY);
          if (cached) {
            const data = JSON.parse(cached);
            if (!cancelled) {
              setBadges(data.badges || []);
              setEarned(data.earned || 0);
              setTotal(data.total || 8);
            }
          }
        } catch {
          // no cache available
        }
      } finally {
        if (!cancelled) setLoading(false);
      }
    }

    fetchBadges();
    return () => { cancelled = true; };
  }, []);

  // Merge server badges with local client-side badges
  const allBadges = useMemo(() => {
    const localEarned = getLocalBadges();
    const localProgress = getLocalProgress();

    const localBadgeObjects = LOCAL_BADGE_DEFS.map(def => ({
      key: def.key,
      label: def.label,
      description: def.description,
      earned: !!localEarned[def.key],
      earned_at: localEarned[def.key]?.earned_at || null,
      progress: localProgress[def.progressKey] || 0,
      threshold: def.threshold,
      isLocal: true,
    }));

    return [...badges, ...localBadgeObjects];
  }, [badges, localBadgeState]); // eslint-disable-line react-hooks/exhaustive-deps

  const totalAll = allBadges.length;
  const earnedAll = allBadges.filter(b => b.earned).length;

  if (loading && allBadges.length === 0) {
    return (
      <div style={{
        backgroundColor: C.surface, border: `1px solid ${C.border}`, borderRadius: 10,
        padding: 20, marginBottom: 20,
      }}>
        <div style={{ fontFamily: mono, fontSize: 13, color: C.textSecondary }}>
          Loading achievements...
        </div>
      </div>
    );
  }

  if (allBadges.length === 0) return null;

  return (
    <div style={{
      backgroundColor: C.surface, border: `1px solid ${C.border}`, borderRadius: 10,
      padding: 20, marginBottom: 20,
    }}>
      {/* Header */}
      <div style={{
        display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 16,
      }}>
        <div style={{
          fontFamily: body, fontSize: 14, fontWeight: 600, color: C.textPrimary,
          textTransform: 'uppercase', letterSpacing: 0.5,
        }}>
          Achievements
        </div>
        <div style={{
          fontFamily: mono, fontSize: 13, color: C.textSecondary,
        }}>
          <span style={{ color: C.green, fontWeight: 700 }}>{earnedAll}</span>
          <span> / {totalAll} earned</span>
        </div>
      </div>

      {/* Progress bar */}
      <div style={{
        width: '100%', height: 4, backgroundColor: C.surface2, borderRadius: 6,
        marginBottom: 16, overflow: 'hidden',
      }}>
        <div style={{
          width: `${totalAll > 0 ? (earnedAll / totalAll) * 100 : 0}%`, height: '100%',
          backgroundColor: C.green, borderRadius: 6, transition: 'width 0.4s ease',
        }} />
      </div>

      {/* Badge Grid */}
      <div className="aura-badge-grid" style={{
        display: 'grid',
        gridTemplateColumns: 'repeat(4, 1fr)',
        gap: 12,
      }}>
        {allBadges.map((badge) => {
          const color = BADGE_COLORS[badge.key] || C.blue;
          const iconFn = BADGE_ICONS[badge.key];
          const isEarned = badge.earned;
          const showTooltip = tooltip === badge.key;
          const hasProgress = badge.isLocal && !isEarned && badge.threshold > 1;

          return (
            <motion.div
              key={badge.key}
              initial={false}
              animate={isEarned ? { scale: [1, 1.05, 1] } : {}}
              transition={{ duration: 0.3 }}
              onClick={() => {
                setTooltip(tooltip === badge.key ? null : badge.key);
              }}
              style={{
                position: 'relative',
                backgroundColor: C.surface2,
                border: `1px solid ${isEarned ? color + '44' : C.border}`,
                borderRadius: 10,
                padding: '16px 12px',
                display: 'flex',
                flexDirection: 'column',
                alignItems: 'center',
                gap: 8,
                cursor: 'pointer',
                filter: isEarned ? 'none' : 'grayscale(1) opacity(0.45)',
                boxShadow: isEarned ? `0 0 12px ${color}22, 0 0 4px ${color}11` : 'none',
                transition: 'all 0.25s ease',
              }}
            >
              {/* Icon */}
              <div style={{
                width: 48, height: 48, borderRadius: '50%',
                backgroundColor: isEarned ? `${color}18` : `${C.border}44`,
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                position: 'relative',
                boxShadow: isEarned ? `0 0 16px ${color}33` : 'none',
              }}>
                {iconFn ? iconFn(isEarned ? color : C.textSecondary) : null}
                {/* Lock overlay for unearned */}
                {!isEarned && (
                  <div style={{
                    position: 'absolute', bottom: -2, right: -2,
                    width: 16, height: 16, borderRadius: '50%',
                    backgroundColor: C.surface, border: `1px solid ${C.border}`,
                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                  }}>
                    <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke={C.textSecondary} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                      <rect x="3" y="11" width="18" height="11" rx="2" ry="2" />
                      <path d="M7 11V7a5 5 0 0 1 10 0v4" />
                    </svg>
                  </div>
                )}
              </div>

              {/* Label */}
              <div style={{
                fontFamily: body, fontSize: 11, fontWeight: 600,
                color: isEarned ? C.textPrimary : C.textSecondary,
                textAlign: 'center', lineHeight: 1.3,
              }}>
                {badge.label}
              </div>

              {/* Description */}
              <div style={{
                fontFamily: body, fontSize: 10, color: C.textSecondary,
                textAlign: 'center', lineHeight: 1.3,
              }}>
                {badge.description}
              </div>

              {/* Progress bar for local unearned badges */}
              {hasProgress && (
                <div style={{ width: '100%', marginTop: 2 }}>
                  <div style={{
                    fontFamily: mono, fontSize: 9, color: C.textSecondary,
                    textAlign: 'center', marginBottom: 3,
                  }}>
                    {badge.progress}/{badge.threshold}
                  </div>
                  <div style={{
                    width: '100%', height: 2, backgroundColor: C.border,
                    borderRadius: 4, overflow: 'hidden',
                  }}>
                    <div style={{
                      width: `${Math.min(100, (badge.progress / badge.threshold) * 100)}%`,
                      height: '100%',
                      backgroundColor: color,
                      borderRadius: 4,
                      transition: 'width 0.3s ease',
                      opacity: 0.6,
                    }} />
                  </div>
                </div>
              )}

              {/* Tooltip — earned date or progress detail */}
              {showTooltip && (
                <div style={{
                  position: 'absolute', bottom: '100%', left: '50%', transform: 'translateX(-50%)',
                  marginBottom: 8, padding: '6px 10px',
                  backgroundColor: C.bg, border: `1px solid ${color}44`,
                  borderRadius: 6, whiteSpace: 'nowrap', zIndex: 10,
                  boxShadow: `0 4px 12px rgba(0,0,0,0.4)`,
                }}>
                  <div style={{ fontFamily: mono, fontSize: 10, color: isEarned ? color : C.textSecondary }}>
                    {isEarned
                      ? `Earned ${formatDate(badge.earned_at)}`
                      : badge.isLocal
                        ? `${badge.progress || 0}/${badge.threshold} - keep going!`
                        : 'Not yet earned'
                    }
                  </div>
                  {/* Arrow */}
                  <div style={{
                    position: 'absolute', top: '100%', left: '50%', transform: 'translateX(-50%)',
                    width: 0, height: 0,
                    borderLeft: '5px solid transparent', borderRight: '5px solid transparent',
                    borderTop: `5px solid ${C.bg}`,
                  }} />
                </div>
              )}
            </motion.div>
          );
        })}
      </div>

      {/* Responsive: 2-col on mobile via inline media query style tag */}
      <style>{`
        @media (max-width: 768px) {
          .aura-badge-grid {
            grid-template-columns: repeat(2, 1fr) !important;
          }
        }
      `}</style>
    </div>
  );
}

// Export progress tracker for use in other components
export { handleBadgeProgress };
